1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const CURSED_SURCHARGE_RATE = 0.5;
12	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const PROCESSING_FEE = 5;
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_BASE = 60;
18	
19	const baseForType = (type: string, count: number): number => {
20	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
21	    return COMPONENT_BLOCK_BASE;
22	  }
23	  return count * BASE_PREMIUMS[type];
24	};
25	
26	export const runScenario = (scenario: any): unknown => {
27	  const items = scenario.steps[0].items;
28	  const countsByType = new Map<string, number>();
29	  for (const item of items) {
30	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
31	  }
32	  let itemBasesSum = 0;
33	  for (const [type, count] of countsByType) {
34	    itemBasesSum += baseForType(type, count);
35	  }
36	  let itemSurcharges = 0;
37	  for (const item of items) {
38	    const itemBase = BASE_PREMIUMS[item.type];
39	    if (item.cursed) {
40	      itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
41	    }
42	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
43	      itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
44	    }
45	  }
46	  const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE + itemSurcharges;
47	  const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
48	  return { results: [{ premium }] };
49	};
